const input = $json.body ?? $json;
const keywordInput = input.keywords ?? input.keyword ?? [];
const keywords = Array.isArray(keywordInput)
  ? keywordInput
  : String(keywordInput)
      .split(/,|\n/)
      .map((keyword) => keyword.trim())
      .filter(Boolean);

const normalizedKeywords = keywords;
if (!normalizedKeywords.length) {
  throw new Error('No keywords were configured for this run.');
}
const lookbackHours = Math.max(1, Number(input.lookbackHours || 24));
const lookbackDays = Math.max(1, Math.ceil(lookbackHours / 24));
const requestedMaxArticles = Number(input.maxArticles);
const maxArticles = Number.isFinite(requestedMaxArticles) && requestedMaxArticles > 0
  ? Math.floor(requestedMaxArticles)
  : null;
const locale = input.locale || 'ja-JP';
const language = input.language || 'ja';
const country = input.country || 'JP';
const outputLanguage = input.outputLanguage || 'ja';
const since = new Date(Date.now() - lookbackHours * 60 * 60 * 1000).toISOString();
const until = new Date().toISOString();
const feedRequests = [];

for (const keyword of normalizedKeywords) {
  const googleQuery = `${keyword} when:${lookbackDays}d`;
  const ceid = `${country}:${language}`;
  const googleNewsRssUrl = `https://news.google.com/rss/search?q=${encodeURIComponent(googleQuery)}&hl=${encodeURIComponent(locale)}&gl=${encodeURIComponent(country)}&ceid=${encodeURIComponent(ceid)}`;
  const hatenaBookmarkRssUrl = `https://b.hatena.ne.jp/search/text?q=${encodeURIComponent(keyword)}&sort=recent&mode=rss`;

  feedRequests.push({
    sourceName: 'Google News',
    keyword,
    query: googleQuery,
    rssUrl: googleNewsRssUrl
  });

  feedRequests.push({
    sourceName: 'Hatena Bookmark',
    keyword,
    query: keyword,
    rssUrl: hatenaBookmarkRssUrl
  });
}

return feedRequests.map((feed) => ({
  json: {
    ...feed,
    keywords: normalizedKeywords,
    since,
    until,
    lookbackHours,
    maxArticles,
    locale,
    language,
    country,
    outputLanguage,
    requestSource: input.source || 'daily-summary-request'
  }
}));

const rssItems = $input.all();
let queryItems = [];

try {
  queryItems = $('Build Search RSS URLs').all().map((item) => item.json);
} catch (error) {
  queryItems = [];
}

const firstQuery = queryItems[0] || {};
const since = firstQuery.since ? new Date(firstQuery.since) : new Date(Date.now() - 24 * 60 * 60 * 1000);
const keywords = firstQuery.keywords || [];
const requestedMaxArticles = Number(firstQuery.maxArticles);
const maxArticles = Number.isFinite(requestedMaxArticles) && requestedMaxArticles > 0
  ? Math.floor(requestedMaxArticles)
  : null;

function cleanText(value) {
  return String(value || '')
    .replace(/<!\[CDATA\[/g, '')
    .replace(/\]\]>/g, '')
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

const seen = new Set();
const articles = [];

for (const item of rssItems) {
  const article = item.json || {};
  const rawDate = article.isoDate || article.pubDate || article.date || article.published || '';
  const publishedAt = rawDate ? new Date(rawDate) : null;

  if (publishedAt && Number.isFinite(publishedAt.getTime()) && publishedAt < since) {
    continue;
  }

  const title = cleanText(article.title);
  const url = article.link || article.guid || '';
  const excerpt = cleanText(article.contentSnippet || article.content || article.description || article.summary);
  const key = url || title.toLowerCase();

  if ((!title && !url) || seen.has(key)) {
    continue;
  }

  seen.add(key);
  articles.push({
    title,
    url,
    publishedAt: publishedAt && Number.isFinite(publishedAt.getTime()) ? publishedAt.toISOString() : rawDate,
    source: cleanText(article.creator || article.author || article['dc:creator'] || ''),
    excerpt: excerpt.slice(0, 700)
  });
}

articles.sort((a, b) => String(b.publishedAt || '').localeCompare(String(a.publishedAt || '')));

return [
  {
    json: {
      generatedAt: new Date().toISOString(),
      period: {
        since: since.toISOString(),
        until: firstQuery.until || new Date().toISOString()
      },
      keywords,
      queryCount: queryItems.length,
      searchSources: Array.from(new Set(queryItems.map((item) => item.sourceName).filter(Boolean))),
      articleCount: articles.length,
      articles: maxArticles ? articles.slice(0, maxArticles) : articles,
      outputLanguage: firstQuery.outputLanguage || 'ja',
      requestSource: firstQuery.requestSource || 'rss'
    }
  }
];

const data = $json;
const articles = Array.isArray(data.articles) ? data.articles : [];
const keywords = Array.isArray(data.keywords) ? data.keywords : [];
const dateLabel = new Date(data.generatedAt || Date.now()).toISOString().slice(0, 10);

const sourceLines = articles.map((article, index) => {
  const parts = [
    `${index + 1}. ${article.title || '(no title)'}`,
    article.publishedAt ? `Published: ${article.publishedAt}` : null,
    article.source ? `Source: ${article.source}` : null,
    article.url ? `URL: ${article.url}` : null,
    article.excerpt ? `Excerpt: ${article.excerpt}` : null
  ].filter(Boolean);

  return parts.join('\n');
});

const topItems = articles.slice(0, 10).map((article, index) => {
  const title = article.title || '(no title)';
  const link = article.url ? ` - ${article.url}` : '';
  const excerpt = article.excerpt ? `\n  ${article.excerpt}` : '';
  return `${index + 1}. ${title}${link}${excerpt}`;
});

const digestMarkdown = [
  `# Daily Keyword News Summary - ${dateLabel}`,
  '',
  `Keywords: ${keywords.join(', ') || '(not available)'}`,
  `Period: ${data.period?.since || ''} to ${data.period?.until || ''}`,
  `Articles found: ${data.articleCount}`,
  '',
  '## Top Items',
  topItems.length ? topItems.join('\n\n') : 'No recent RSS items were found for the configured keywords.',
  '',
  '## Source URLs',
  articles.map((article) => `- ${article.title || article.url}: ${article.url || '(no URL)'}`).join('\n') || '- No URLs'
].join('\n');

const llmPrompt = [
  `You are preparing a daily news and web-content digest in ${data.outputLanguage || 'ja'}.`,
  `Summarize only the sources listed below. Do not invent facts or add uncited claims.`,
  `Target keywords: ${keywords.join(', ') || '(not available)'}`,
  `Time window: ${data.period?.since || ''} to ${data.period?.until || ''}`,
  'Return the digest with these sections: 1) Executive summary, 2) Important developments by keyword, 3) Source-by-source notes, 4) Items to monitor tomorrow.',
  'For each important claim, mention the source title or URL.',
  '',
  'Sources:',
  sourceLines.join('\n\n') || 'No source items were found.'
].join('\n');

return [
  {
    json: {
      ...data,
      digestMarkdown,
      llmPrompt,
      nextAutomationSteps: [
        'Connect llmPrompt to an OpenAI, Anthropic, Gemini, or HTTP Request node for semantic summarization.',
        'Send digestMarkdown or the LLM output to Gmail, Slack, Notion, Google Docs, or WordPress.',
        'Add a duplicate-history store if the same articles should not appear across multiple days.'
      ]
    }
  }
];

const data = $json;
const knownTerms = [
  { term: 'ホロライブ', aliases: ['ホロライブ', 'hololive'], category: 'agency/group' },
  { term: 'COVER', aliases: ['COVER', 'カバー株式会社', 'カバー'], category: 'company' },
  { term: 'ANYCOLOR', aliases: ['ANYCOLOR', 'ANYCOLOR株式会社'], category: 'company' },
  { term: 'NIJISANJI EN', aliases: ['NIJISANJI EN', 'にじさんじEN'], category: 'agency/group' },
  { term: 'ぶいすぽっ!', aliases: ['ぶいすぽっ!', 'ぶいすぽ', 'VSPO!'], category: 'agency/group' },
  { term: 'Brave group', aliases: ['Brave group', 'BraveGroup'], category: 'company' },
  { term: 'あおぎり高校', aliases: ['あおぎり高校'], category: 'agency/group' },
  { term: 'ななしいんく', aliases: ['ななしいんく', '774inc'], category: 'agency/group' },
  { term: 'Neo-Porte', aliases: ['Neo-Porte', 'ネオポルテ'], category: 'agency/group' },
  { term: 'VShojo', aliases: ['VShojo'], category: 'agency/group' },
  { term: 'Phase Connect', aliases: ['Phase Connect'], category: 'agency/group' },
  { term: '.LIVE', aliases: ['.LIVE', 'どっとライブ'], category: 'agency/group' },
  { term: 'のりプロ', aliases: ['のりプロ'], category: 'agency/group' },
  { term: 'RIOT MUSIC', aliases: ['RIOT MUSIC'], category: 'agency/group' },
  { term: 'Re:AcT', aliases: ['Re:AcT', 'ReAct'], category: 'agency/group' },
  { term: 'VOMS', aliases: ['VOMS'], category: 'agency/group' },
  { term: '深層組', aliases: ['深層組'], category: 'agency/group' },
  { term: 'Varium', aliases: ['Varium', 'ぶいありうむっ！'], category: 'agency/group' },
  { term: 'ホロスターズ', aliases: ['ホロスターズ', 'HOLOSTARS'], category: 'agency/group' },
  { term: 'ChroNoiR', aliases: ['ChroNoiR', 'クロノワール'], category: 'unit' },
  { term: 'ROF-MAO', aliases: ['ROF-MAO', 'ろふまお'], category: 'unit' },
  { term: 'Live2D', aliases: ['Live2D'], category: 'technology' }
];
const stopTerms = new Set(['https', 'http', 'www', 'com', 'ニュース', 'まとめ', '記事', '動画', '配信', '発表', '開催', '公開', 'YouTube']);

function jstDateParts(value) {
  const date = value ? new Date(value) : new Date();
  const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone: 'Asia/Tokyo', year: 'numeric', month: '2-digit', day: '2-digit'
  });
  const parts = Object.fromEntries(formatter.formatToParts(date).map((part) => [part.type, part.value]));
  return { date: `${parts.year}-${parts.month}-${parts.day}` };
}

function slugifyKeywords(keywords) {
  return (keywords || [])
    .map((keyword) => String(keyword).trim())
    .filter(Boolean)
    .join('-')
    .toLowerCase()
    .replace(/[\\/:*?"<>|`$&;(){}[\]\n\r\t]+/g, '-')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 90) || 'daily-summary';
}

function frontMatter(dateLabel) {
  const keywords = Array.isArray(data.keywords) ? data.keywords : [];
  const sources = Array.isArray(data.searchSources) ? data.searchSources : [];
  return [
    '---',
    'title: "Daily Keyword News Summary"',
    `date: "${dateLabel}"`,
    `generatedAt: "${data.generatedAt || new Date().toISOString()}"`,
    'keywords:',
    ...(keywords.length ? keywords.map((keyword) => `  - "${String(keyword).replace(/"/g, '\\"')}"`) : ['  - ""']),
    'sources:',
    ...(sources.length ? sources.map((source) => `  - "${String(source).replace(/"/g, '\\"')}"`) : ['  - ""']),
    `articleCount: ${Number(data.articleCount || 0)}`,
    '---',
    ''
  ].join('\n');
}

function articleListMarkdown(articles) {
  if (!articles.length) {
    return 'No articles were captured for this run.';
  }
  return articles.map((article, index) => [
    `### ${index + 1}. ${article.title || '(no title)'}`,
    '',
    article.url ? `- URL: ${article.url}` : null,
    article.publishedAt ? `- Published: ${article.publishedAt}` : null,
    article.source ? `- Source: ${article.source}` : null,
    '',
    article.excerpt || null
  ].filter((line) => line !== null).join('\n')).join('\n\n');
}

function buildDigestMarkdown(dateLabel) {
  const articles = Array.isArray(data.articles) ? data.articles : [];
  const period = data.period || {};
  return [
    frontMatter(dateLabel),
    data.digestMarkdown || `# Daily Keyword News Summary - ${dateLabel}`,
    '',
    '## Run Metadata',
    '',
    `- Generated at: ${data.generatedAt || ''}`,
    `- Period start: ${period.since || ''}`,
    `- Period end: ${period.until || ''}`,
    `- Article count: ${Number(data.articleCount || articles.length)}`,
    `- Search sources: ${(data.searchSources || []).join(', ') || '(not available)'}`,
    '',
    '## Captured Articles',
    '',
    articleListMarkdown(articles),
    '',
    '## LLM Prompt',
    '',
    '<details>',
    '<summary>Prompt used for semantic summarization</summary>',
    '',
    '```text',
    data.llmPrompt || '',
    '```',
    '',
    '</details>',
    ''
  ].join('\n');
}

function escapeRegExp(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function collectSourceReferences(articles, term) {
  const refs = [];
  const lowerTerm = String(term).toLowerCase();
  for (const article of articles) {
    const haystack = `${article.title || ''}\n${article.excerpt || ''}\n${article.source || ''}`.toLowerCase();
    if (haystack.includes(lowerTerm)) {
      refs.push(article.title || article.url || '(untitled source)');
    }
    if (refs.length >= 3) break;
  }
  return refs;
}

function addCandidate(candidates, currentKeywords, term, category, reason, sourceRefs = []) {
  const normalized = String(term || '').trim();
  if (!normalized || normalized.length < 2) return;
  const lower = normalized.toLowerCase();
  if (stopTerms.has(normalized) || currentKeywords.has(lower)) return;
  const existing = candidates.get(lower);
  if (existing) {
    existing.count += 1;
    existing.reasons.add(reason);
    sourceRefs.forEach((source) => existing.sources.add(source));
    return;
  }
  candidates.set(lower, { term: normalized, category, count: 1, reasons: new Set([reason]), sources: new Set(sourceRefs) });
}

function extractSourceTerms(text) {
  const terms = new Set();
  for (const match of text.matchAll(/#([A-Za-z0-9_\-\u3040-\u30ff\u3400-\u9fff]{2,40})/g)) terms.add(match[1]);
  for (const match of text.matchAll(/\b[A-Z][A-Za-z0-9&.:'!-]{2,30}\b/g)) terms.add(match[0]);
  for (const match of text.matchAll(/[ァ-ヴー]{3,20}/g)) terms.add(match[0]);
  for (const match of text.matchAll(/[一-龠々〆ヵヶ]{2,12}(?:事務所|プロ|高校|会社|株式会社|グループ|運営|所属)/g)) terms.add(match[0]);
  return [...terms];
}

function extractKeywordCandidates(markdown) {
  const articles = Array.isArray(data.articles) ? data.articles : [];
  const currentKeywords = new Set((data.keywords || []).map((keyword) => String(keyword).toLowerCase()));
  const candidates = new Map();

  for (const known of knownTerms) {
    let count = 0;
    for (const alias of known.aliases || [known.term]) {
      const matches = markdown.match(new RegExp(escapeRegExp(alias), 'gi'));
      count += matches ? matches.length : 0;
    }
    if (count > 0) {
      addCandidate(candidates, currentKeywords, known.term, known.category, `known VTuber-related term appeared ${count} time(s)`, collectSourceReferences(articles, known.term));
      const candidate = candidates.get(known.term.toLowerCase());
      if (candidate) candidate.count = count;
    }
  }

  const sourceText = articles.map((article) => `${article.title || ''}\n${article.excerpt || ''}\n${article.source || ''}`).join('\n');
  for (const term of extractSourceTerms(sourceText)) {
    if (term.length > 30 || /^\d+$/.test(term)) continue;
    addCandidate(candidates, currentKeywords, term, 'source-derived', 'appeared in captured article text', collectSourceReferences(articles, term));
  }

  return [...candidates.values()].map((candidate) => ({
    term: candidate.term,
    category: candidate.category,
    count: candidate.count,
    reasons: [...candidate.reasons],
    sources: [...candidate.sources]
  })).sort((a, b) => b.count - a.count || a.term.localeCompare(b.term, 'ja')).slice(0, 40);
}



function buildAiSummaryInstructionMarkdown(dateLabel, digestRelativePath, digestMarkdown) {
  const articles = Array.isArray(data.articles) ? data.articles : [];
  const currentKeywords = Array.isArray(data.keywords) ? data.keywords : [];
