  const sourceContext = articles.map((article, index) => ({
    index: index + 1,
    title: article.title || '',
    url: article.url || '',
    publishedAt: article.publishedAt || '',
    source: article.source || '',
    excerpt: article.excerpt || ''
  }));

  return [
