    '',
    '- 明日以降も追うべき話題、イベント、企業名、ユニット名など。',
    '````',
    '',
    '### 注意事項',
    '',
    '- 入力に含まれない情報を追加しない',
    '- 情報源がYouTubeやSNS由来の場合は、その点が分かるように書く',
    '- 同一内容の記事はまとめ、重複して長くしない',
    '- 出力は日本語で作成する',
    '',
    '## 取得記事一覧（構造化データ）',
    '',
    '```json',
    JSON.stringify(sourceContext, null, 2),
    '```',
    '',
    '## 入力Digest',
    '',
    '```markdown',
    digestMarkdown,
    '```',
    ''
  ].join('\n');
}

function buildAiExtractionInstructionMarkdown(dateLabel, digestRelativePath, candidateRelativePath, digestMarkdown, candidates) {
  const currentKeywords = Array.isArray(data.keywords) ? data.keywords : [];
  const candidateContext = candidates.length
    ? candidates.map((candidate) => ({
        term: candidate.term,
        category: candidate.category,
        count: candidate.count,
        reasons: candidate.reasons,
        sources: candidate.sources.slice(0, 3)
      }))
    : [];

  return [
    '---',
    'title: "AI Keyword Extraction Instructions"',
    `date: "${dateLabel}"`,
    `sourceDigest: "${digestRelativePath}"`,
    `ruleBasedCandidates: "${candidateRelativePath}"`,
    '---',
    '',
    `# AI Keyword Extraction Instructions - ${dateLabel}`,
