return [{ json: { status: 'added', keyword, reason: 'Saved to workflow static data.', added: true, autoKeywordCount: autoKeywords.length } }];

const webhook = $('Keyword Management Webhook').first().json ?? {};
const body = webhook.body ?? webhook;
const operation = String(body.operation ?? '').trim().toLowerCase();
let keyword = String(body.keyword ?? '').trim();
const previousKeyword = String(body.previousKeyword ?? '').trim();
const source = String(body.source ?? '').trim();
const config = $input.first().json.keywordConfig ?? {};
const normalize = (value) => String(value || '').trim().replaceAll('！', '!').toLocaleLowerCase('ja-JP');
const terms = (value) => { const seen = new Set(); return (Array.isArray(value) ? value : String(value ?? '').split(/,|\n/)).reduce((all, value) => { const term = String(value || '').trim(); const key = normalize(term); if (term && !seen.has(key)) { seen.add(key); all.push(term); } return all; }, []); };
const manualKeywords = terms(config.manualKeywords);
const excludedKeywords = new Set(terms(config.excludedKeywords).map(normalize));
const maxAutoKeywords = Math.max(0, Math.floor(Number(config.maxAutoKeywords ?? 30) || 0));
const staticData = $getWorkflowStaticData('global');
const autoKeywords = terms(staticData.autoKeywords);
const respond = (status, reason, value = keyword || previousKeyword, changed = false) => [{ json: { status, keyword: value, reason, changed, autoKeywordCount: autoKeywords.length } }];
const validKeyword = (value) => value.length >= 2 && value.length <= 30 && !/[|/\\]/.test(value) && !/^https?:/i.test(value);

if (source !== 'talent-dashboard') return respond('rejected', 'This webhook only accepts requests from the local Talent Index dashboard.');
if (!['add', 'edit', 'remove'].includes(operation)) return respond('rejected', 'operation must be add, edit, or remove.');
if (operation !== 'remove' && !validKeyword(keyword)) return respond('rejected', 'The keyword format is not allowed.');
if ((operation === 'edit' || operation === 'remove') && !previousKeyword) return respond('rejected', 'previousKeyword is required.');
if (operation !== 'remove' && excludedKeywords.has(normalize(keyword))) return respond('rejected', 'The keyword is excluded by config/keywords.json.');
if (operation !== 'remove' && manualKeywords.some((term) => normalize(term) === normalize(keyword))) return respond('already_added', 'The keyword is already configured manually.');

let status = 'rejected';
let reason = '';
let changed = false;
if (operation === 'add') {
  if (autoKeywords.some((term) => normalize(term) === normalize(keyword))) return respond('already_added', 'The keyword is already configured.');
  if (autoKeywords.length >= maxAutoKeywords) return respond('rejected', `The automatic keyword limit (${maxAutoKeywords}) has been reached.`);
  autoKeywords.push(keyword);
  status = 'added'; reason = 'Saved to workflow static data.'; changed = true;
} else {
  const index = autoKeywords.findIndex((term) => normalize(term) === normalize(previousKeyword));
  if (index < 0) return respond(operation === 'remove' ? 'already_removed' : 'rejected', operation === 'remove' ? 'The keyword was already removed.' : 'The keyword no longer exists.');
  if (operation === 'remove') {
    const removed = autoKeywords.splice(index, 1)[0];
    keyword = removed;
    status = 'removed'; reason = 'Removed from workflow static data.'; changed = true;
  } else if (normalize(autoKeywords[index]) === normalize(keyword)) {
    return respond('unchanged', 'The keyword did not change.', autoKeywords[index]);
  } else if (autoKeywords.some((term, position) => position !== index && normalize(term) === normalize(keyword))) {
    return respond('rejected', 'The keyword already exists.');
  } else {
    autoKeywords[index] = keyword;
    status = 'updated'; reason = 'Updated in workflow static data.'; changed = true;
  }
}

if (changed) {
  staticData.autoKeywords = autoKeywords;
  const history = Array.isArray(staticData.dashboardKeywordManagement) ? staticData.dashboardKeywordManagement : [];
  staticData.dashboardKeywordManagement = [...history, { operation, keyword, previousKeyword, changedAt: new Date().toISOString() }].slice(-100);
  staticData.lastDashboardKeywordManagement = staticData.dashboardKeywordManagement.at(-1);
}
return respond(status, reason, keyword, changed);
